-- Seed complementario para asociaciones entre puntos de reciclaje, tipos de tacho
-- y la correspondencia institucional waste_type -> bin_type.

on conflict (recycling_point_id, bin_type_id) do update set
  is_active = excluded.is_active,
  updated_at = now();

on conflict (university_id, waste_type_id, bin_type_id) do update set
  is_active = excluded.is_active,
  updated_at = now();
